17: package org.apache.kafka.clients.consumer.internals;
18: 
19: import org.apache.kafka.clients.consumer.ConsumerRebalanceListener;
20: import org.apache.kafka.clients.consumer.internals.metrics.RebalanceCallbackMetricsManager;
21: import org.apache.kafka.common.TopicPartition;
22: import org.apache.kafka.common.errors.InterruptException;
23: import org.apache.kafka.common.errors.WakeupException;
24: import org.apache.kafka.common.metrics.Sensor;
25: import org.apache.kafka.common.utils.LogContext;
26: import org.apache.kafka.common.utils.Time;
27: 
28: import org.slf4j.Logger;
29: 
30: import java.util.Optional;
31: import java.util.Set;
32: import java.util.SortedSet;
33: 
34: /**
35:  * This class encapsulates the invocation of the callback methods defined in the {@link ConsumerRebalanceListener}
36:  * interface. When consumer group partition assignment changes, these methods are invoked. This class wraps those
37:  * callback calls with some logging, optional {@link Sensor} updates, etc.
38:  */
39: public class ConsumerRebalanceListenerInvoker {
40: 
41:     private final Logger log;
42:     private final SubscriptionState subscriptions;
43:     private final Time time;
44:     private final RebalanceCallbackMetricsManager metricsManager;
45: 
46:     ConsumerRebalanceListenerInvoker(LogContext logContext,
47:                                      SubscriptionState subscriptions,
48:                                      Time time,
49:                                      RebalanceCallbackMetricsManager metricsManager) {
50:         this.log = logContext.logger(getClass());
51:         this.subscriptions = subscriptions;
52:         this.time = time;
53:         this.metricsManager = metricsManager;
54:     }
55: 
56:     public Exception invokePartitionsAssigned(final SortedSet<TopicPartition> assignedPartitions) {
57:         log.info("Adding newly assigned partitions: {}", assignedPartitions);
58: 
59:         Optional<ConsumerRebalanceListener> listener = subscriptions.rebalanceListener();
60: 
61:         if (listener.isPresent()) {
62:             try {
63:                 final long startMs = time.milliseconds();
64:                 listener.get().onPartitionsAssigned(assignedPartitions);
65:                 metricsManager.recordPartitionsAssignedLatency(time.milliseconds() - startMs);
66:             } catch (WakeupException | InterruptException e) {
67:                 throw e;
68:             } catch (Exception e) {
69:                 log.error(
70:                     "User provided listener {} failed on invocation of onPartitionsAssigned for partitions {}",
71:                     listener.get().getClass().getName(),
72:                     assignedPartitions,
73:                     e
74:                 );
75:                 return e;
76:             }
77:         }
78: 
79:         return null;
80:     }
81: 
82:     public Exception invokePartitionsRevoked(final SortedSet<TopicPartition> revokedPartitions) {
83:         log.info("Revoke previously assigned partitions {}", revokedPartitions);
84:         Set<TopicPartition> revokePausedPartitions = subscriptions.pausedPartitions();
85:         revokePausedPartitions.retainAll(revokedPartitions);
86:         if (!revokePausedPartitions.isEmpty())
87:             log.info("The pause flag in partitions {} will be removed due to revocation.", revokePausedPartitions);
88: 
89:         Optional<ConsumerRebalanceListener> listener = subscriptions.rebalanceListener();
90: 
91:         if (listener.isPresent()) {
92:             try {
93:                 final long startMs = time.milliseconds();
94:                 listener.get().onPartitionsRevoked(revokedPartitions);
95:                 metricsManager.recordPartitionsRevokedLatency(time.milliseconds() - startMs);
96:             } catch (WakeupException | InterruptException e) {
97:                 throw e;
98:             } catch (Exception e) {
99:                 log.error(
100:                     "User provided listener {} failed on invocation of onPartitionsRevoked for partitions {}",
101:                     listener.get().getClass().getName(),
102:                     revokedPartitions,
103:                     e
104:                 );
105:                 return e;
106:             }
107:         }
108: 
109:         return null;
110:     }
111: 
112:     public Exception invokePartitionsLost(final SortedSet<TopicPartition> lostPartitions) {
113:         log.info("Lost previously assigned partitions {}", lostPartitions);
114:         Set<TopicPartition> lostPausedPartitions = subscriptions.pausedPartitions();
115:         lostPausedPartitions.retainAll(lostPartitions);
116:         if (!lostPausedPartitions.isEmpty())
117:             log.info("The pause flag in partitions {} will be removed due to partition lost.", lostPartitions);
118: 
119:         Optional<ConsumerRebalanceListener> listener = subscriptions.rebalanceListener();
120: 
121:         if (listener.isPresent()) {
122:             try {
123:                 final long startMs = time.milliseconds();
124:                 listener.get().onPartitionsLost(lostPartitions);
125:                 metricsManager.recordPartitionsLostLatency(time.milliseconds() - startMs);
126:             } catch (WakeupException | InterruptException e) {
127:                 throw e;
128:             } catch (Exception e) {
129:                 log.error(
130:                     "User provided listener {} failed on invocation of onPartitionsLost for partitions {}",
131:                     listener.get().getClass().getName(),
132:                     lostPartitions,
133:                     e
134:                 );
135:                 return e;
136:             }
137:         }
138: 
139:         return null;
140:     }
141: }
